package com.teamspace.teamspace.task.service;
import java.util.List; import org.springframework.security.core.Authentication; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import com.teamspace.teamspace.exception.*; import com.teamspace.teamspace.task.dto.TaskWatcherResponse; import com.teamspace.teamspace.task.entity.*; import com.teamspace.teamspace.task.repository.*; import com.teamspace.teamspace.user.entity.User; import com.teamspace.teamspace.user.repository.UserRepository; import com.teamspace.teamspace.workspace.repository.WorkspaceMemberRepository; import lombok.RequiredArgsConstructor;
@Service @RequiredArgsConstructor public class TaskWatcherService {private final TaskWatcherRepository repository;private final TaskRepository taskRepository;private final UserRepository userRepository;private final WorkspaceMemberRepository memberRepository;
 @Transactional(readOnly=true)public List<TaskWatcherResponse> list(Long id,Authentication a){Task t=task(id);member(t,user(a));return repository.findByTaskIdOrderByCreatedAtAsc(id).stream().map(TaskWatcherResponse::from).toList();}
 @Transactional public TaskWatcherResponse follow(Long id,Authentication a){Task t=task(id);User u=user(a);member(t,u);TaskWatcher w=repository.findByTaskIdAndUserId(id,u.getId()).orElseGet(()->repository.save(TaskWatcher.builder().task(t).user(u).build()));return TaskWatcherResponse.from(w);}
 @Transactional public void unfollow(Long id,Authentication a){Task t=task(id);User u=user(a);member(t,u);repository.findByTaskIdAndUserId(id,u.getId()).ifPresent(repository::delete);}
 @Transactional public void autoFollow(Task t,User u){if(u!=null&&!repository.existsByTaskIdAndUserId(t.getId(),u.getId()))repository.save(TaskWatcher.builder().task(t).user(u).build());}
 private Task task(Long id){return taskRepository.findById(id).orElseThrow(()->new ResourceNotFoundException("Khong tim thay task"));}private User user(Authentication a){if(a==null)throw new UnauthorizedException("Ban chua dang nhap");return userRepository.findByEmail(a.getName()).orElseThrow(()->new UnauthorizedException("Khong tim thay user"));}private void member(Task t,User u){if(!memberRepository.existsByWorkspaceIdAndUserId(t.getProject().getWorkspace().getId(),u.getId()))throw new ForbiddenException("Ban khong thuoc du an");}}
